/**
 * Format a macro value with at most 2 decimals and at most 3 significant
 * figures in the decimal part. Examples: 1.23, 12.3, 123, 12345.
 *
 * Use for display only — stored values stay as full floats.
 */
export function formatMacro(value: number): string {
    if (!Number.isFinite(value) || value === 0) return '0';
    const abs = Math.abs(value);
    if (abs >= 100) return String(Math.round(value));
    const decimals = abs >= 10 ? 1 : 2;
    return Number(value.toFixed(decimals)).toString();
}
